 16	// writeMinimalConfig creates the minimum .ddx/config.yaml a queryResolver needs
 17	// so agent.NewServiceFromWorkDir can load. No endpoints configured.
 18	func writeMinimalConfig(t *testing.T, workDir string) {
 19		t.Helper()
 20		ddxDir := filepath.Join(workDir, ".ddx")
 21		if err := os.MkdirAll(ddxDir, 0o755); err != nil {
 22			t.Fatal(err)
 23		}
 24		cfg := "version: \"1.0\"\nbead:\n  id_prefix: \"pt\"\n"
 25		if err := os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte(cfg), 0o644); err != nil {
 26			t.Fatal(err)
 27		}
 28	}
 29	
 30	func writeEndpointConfig(t *testing.T, workDir string) string {
 31		t.Helper()
 32		ddxDir := filepath.Join(workDir, ".ddx")
 33		if err := os.MkdirAll(ddxDir, 0o755); err != nil {
 34			t.Fatal(err)
 35		}
 36		cfg := `version: "1.0"
 37	bead:
 38	  id_prefix: "pt"
 39	agent:
 40	  endpoints:
 41	    - type: lmstudio
 42	      base_url: http://127.0.0.1:9/v1
 43	`
 44		if err := os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte(cfg), 0o644); err != nil {
 45			t.Fatal(err)
 46		}
 47		return "lmstudio-127-0-0-1-9"
 48	}
